'use client'
import { useState, useEffect, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'

const VIKTORIA_IMG = "data:image/png;base64,"

const MESSAGES = [
  "Ahoj! Jsem Viktória ✨ Přijedu za Vámi domů!",
  "Klasické řasy od 499 Kč 💕",
  "Mega Volume — absolutní extravagance ✸",
  "Wet Look — trendový efekt! 💧",
  "Rezervujte online 24/7 → /rezervace",
  "Oblast: Mladá Boleslav & okolí 🏠",
  "Přijedu přímo k Vám — komfort na prvním místě!",
  "Doplnění řas od 199 Kč ◉",
  "Máte dotaz? Zavolejte: +420 720 307 007",
]

interface Particle { id: number; x: number; y: number; color: string; size: number }

export function ViktoriaChatbot() {
  const [open, setOpen] = useState(false)
  const [msgIdx, setMsgIdx] = useState(0)
  const [typing, setTyping] = useState(false)
  const [particles, setParticles] = useState<Particle[]>([])
  const [hovered, setHovered] = useState(false)
  const [mood, setMood] = useState<'idle'|'wave'|'wink'|'happy'>('idle')
  const particleId = useRef(0)

  // Rotate messages
  useEffect(() => {
    if (!open) return
    const t = setInterval(() => {
      setTyping(true)
      setTimeout(() => {
        setMsgIdx(i => (i + 1) % MESSAGES.length)
        setTyping(false)
      }, 1200)
    }, 5000)
    return () => clearInterval(t)
  }, [open])

  // Spawn particles on hover
  useEffect(() => {
    if (!hovered) return
    const t = setInterval(() => {
      const id = particleId.current++
      const colors = ['#FF6BA8','#E8A4BE','#D4AA70','#ffffff']
      setParticles(p => [...p.slice(-12), {
        id, x: 20 + Math.random() * 60,
        y: Math.random() * 100,
        color: colors[Math.floor(Math.random() * colors.length)],
        size: 3 + Math.random() * 5,
      }])
      setTimeout(() => setParticles(p => p.filter(x => x.id !== id)), 1500)
    }, 120)
    return () => clearInterval(t)
  }, [hovered])

  const handleOpen = () => {
    setOpen(o => !o)
    setMood('wave')
    setTimeout(() => setMood('idle'), 2000)
  }

  return (
    <div style={{ position:'fixed', bottom:24, right:24, zIndex:9000, display:'flex', flexDirection:'column', alignItems:'flex-end', gap:12 }}>
      
      {/* Chat bubble */}
      <AnimatePresence>
        {open && (
          <motion.div
            initial={{ opacity:0, y:20, scale:0.9 }}
            animate={{ opacity:1, y:0, scale:1 }}
            exit={{ opacity:0, y:10, scale:0.95 }}
            transition={{ duration:0.3, ease:[0.16,1,0.3,1] }}
            style={{
              background:'rgba(8,6,8,0.95)',
              border:'1px solid rgba(255,107,168,0.4)',
              borderRadius:'20px 20px 4px 20px',
              padding:'14px 18px',
              maxWidth:240,
              backdropFilter:'blur(20px)',
              boxShadow:'0 0 40px rgba(255,107,168,0.2)',
            }}
          >
            <div style={{ fontFamily:'Georgia,serif', fontSize:10, letterSpacing:3, color:'#FF6BA8', textTransform:'uppercase', marginBottom:6, textShadow:'0 0 10px rgba(255,107,168,0.6)' }}>
              ✦ Viktória
            </div>
            <AnimatePresence mode="wait">
              {typing ? (
                <motion.div key="typing" initial={{opacity:0}} animate={{opacity:1}} exit={{opacity:0}}
                  style={{ display:'flex', gap:4, alignItems:'center', padding:'4px 0' }}>
                  {[0,1,2].map(i => (
                    <motion.div key={i} animate={{ y:[0,-4,0] }} transition={{ duration:0.5, delay:i*0.15, repeat:Infinity }}
                      style={{ width:5, height:5, borderRadius:'50%', background:'rgba(255,107,168,0.6)' }}/>
                  ))}
                </motion.div>
              ) : (
                <motion.p key={msgIdx} initial={{opacity:0,y:8}} animate={{opacity:1,y:0}} exit={{opacity:0,y:-8}}
                  transition={{duration:0.4}}
                  style={{ fontFamily:'Georgia,serif', fontSize:13, color:'rgba(245,238,242,0.9)', lineHeight:1.6, margin:0 }}>
                  {MESSAGES[msgIdx]}
                </motion.p>
              )}
            </AnimatePresence>
            <a href="/rezervace" style={{
              display:'inline-block', marginTop:10,
              fontFamily:'Georgia,serif', fontSize:10, letterSpacing:2,
              color:'#FF6BA8', textDecoration:'none', textTransform:'uppercase',
              borderBottom:'1px solid rgba(255,107,168,0.4)',
            }}>
              Rezervovat →
            </a>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Avatar button */}
      <div style={{ position:'relative' }}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}>

        {/* Particles */}
        {particles.map(p => (
          <motion.div key={p.id}
            initial={{ opacity:0.9, y:0, x:p.x, scale:1 }}
            animate={{ opacity:0, y:-60, scale:0 }}
            transition={{ duration:1.5, ease:'easeOut' }}
            style={{
              position:'absolute', bottom:0, left:0,
              width:p.size, height:p.size, borderRadius:'50%',
              background:p.color, boxShadow:`0 0 ${p.size*2}px ${p.color}`,
              pointerEvents:'none', zIndex:1,
            }}
          />
        ))}

        {/* Glow ring */}
        <motion.div
          animate={{ boxShadow: hovered
            ? '0 0 0 3px rgba(255,107,168,0.6), 0 0 30px rgba(255,107,168,0.4), 0 0 60px rgba(255,107,168,0.2)'
            : open
              ? '0 0 0 2px rgba(255,107,168,0.4), 0 0 20px rgba(255,107,168,0.3)'
              : '0 0 0 1px rgba(255,107,168,0.2), 0 0 15px rgba(255,107,168,0.15)',
          }}
          transition={{ duration:0.3 }}
          style={{ borderRadius:'50%', cursor:'none' }}
          onClick={handleOpen}
        >
          {/* Rotating sparkle ring */}
          <motion.div
            animate={{ rotate: 360 }}
            transition={{ duration:8, repeat:Infinity, ease:'linear' }}
            style={{
              position:'absolute', inset:-6, borderRadius:'50%',
              border:'1px dashed rgba(255,107,168,0.3)',
              pointerEvents:'none',
            }}
          >
            {['✦','✸','◈'].map((s,i) => (
              <div key={i} style={{
                position:'absolute',
                fontSize:8, color:'#FF6BA8',
                top: i===0?-4 : i===1?'45%':'85%',
                left: i===0?'45%' : i===1?i===1?-6:0 : '40%',
                textShadow:'0 0 8px #FF6BA8',
              }}>{s}</div>
            ))}
          </motion.div>

          {/* Photo */}
          <motion.div
            animate={{
              y: mood==='wave' ? [0,-8,0,-5,0] : [0,-4,0],
            }}
            transition={{
              duration: mood==='wave' ? 0.8 : 4,
              repeat: mood==='wave' ? 0 : Infinity,
              ease:'easeInOut',
            }}
            style={{
              width:90, height:90, borderRadius:'50%', overflow:'hidden',
              border:'2px solid rgba(255,107,168,0.5)',
              position:'relative',
            }}
          >
            <img
              src={VIKTORIA_IMG}
              alt="Viktória"
              style={{
                width:'180%', height:'180%',
                objectFit:'cover',
                objectPosition:'center top',
                marginLeft:'-40%',
                marginTop:'-15%',
                filter: hovered ? 'brightness(1.1) contrast(1.05)' : 'brightness(1)',
                transition:'filter 0.3s',
              }}
            />
          </motion.div>
        </motion.div>

        {/* Name tag */}
        <AnimatePresence>
          {hovered && (
            <motion.div
              initial={{opacity:0,y:5}} animate={{opacity:1,y:0}} exit={{opacity:0,y:5}}
              style={{
                position:'absolute', bottom:-22, left:'50%', transform:'translateX(-50%)',
                fontFamily:'Georgia,serif', fontSize:9, letterSpacing:3,
                color:'#FF6BA8', textTransform:'uppercase', whiteSpace:'nowrap',
                textShadow:'0 0 10px rgba(255,107,168,0.6)',
              }}>
              Viktória ✦
            </motion.div>
          )}
        </AnimatePresence>
      </div>
    </div>
  )
}
